import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://sumbbvlxsyxcqpijjymk.supabase.co';
const supabaseKey = 'sb_publishable_3HvRl7Klpj4R-jk-z80lig_Y2SpN41y';

export const supabase = createClient(supabaseUrl, supabaseKey);

import { supabase } from './supabase';

// Helper to check if we have a user session
const getUserId = async () => {
  const { data } = await supabase.auth.getSession();
  return data.session?.user?.id;
};

export const StorageService = {
  // Synchronous read (keeps app fast and works with existing logic)
  getItem: (key: string): string | null => {
    return localStorage.getItem(key);
  },

  // Dual write: LocalStorage (Instant) + Supabase (Async Background)
  setItem: async (key: string, value: string) => {
    // 1. Update LocalStorage immediately so UI reflects changes
    localStorage.setItem(key, value);

    // 2. Sync to Supabase if logged in
    const userId = await getUserId();
    if (userId) {
      try {
        // We store the value as a JSON object inside the 'data' column
        // If the value is a stringified JSON, we parse it, otherwise we store it as a string
        let dataToStore;
        try {
            dataToStore = JSON.parse(value);
        } catch (e) {
            dataToStore = value;
        }

        const { error } = await supabase
          .from('user_data')
          .upsert({ 
            user_id: userId, 
            key: key, 
            data: dataToStore,
            updated_at: new Date().toISOString()
          }, { onConflict: 'user_id, key' });

        if (error) console.error('Supabase Sync Error:', error);
      } catch (err) {
        console.error('Storage Service Error:', err);
      }
    }
  },

  removeItem: async (key: string) => {
    localStorage.removeItem(key);

    const userId = await getUserId();
    if (userId) {
      await supabase.from('user_data').delete().eq('user_id', userId).eq('key', key);
    }
  },

  clear: () => {
    localStorage.clear();
    // We do not clear Supabase on local clear, as that would wipe the account data.
    // This is typically called on Logout.
  },

  // Bulk Load (Called on Login)
  syncFromRemote: async () => {
    const userId = await getUserId();
    if (!userId) return;

    const { data, error } = await supabase.from('user_data').select('key, data');

    if (error) {
        console.error("Error fetching data:", error);
        return;
    }

    if (data) {
        // Clear local first to avoid stale data from previous user
        localStorage.clear();

        data.forEach(row => {
            const val = typeof row.data === 'string' ? row.data : JSON.stringify(row.data);
            localStorage.setItem(row.key, val);
        });
    }
  }
};

