                                        <div key={log.id} className="p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30">
                                            <div className="flex justify-between items-center"><span className="font-bold text-lg text-gray-800 dark:text-white">{log.systolic}/{log.diastolic}</span><span className={`text-xs font-bold ${status.color}`}>{status.label}</span></div>
                                            <div className="text-xs text-gray-400 mt-1">{new Date(log.date).toLocaleDateString()}</div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                        <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
                            <h4 className="font-bold text-purple-700 dark:text-purple-400 mb-4 flex items-center gap-2"><Droplet /> Blood Glucose</h4>
                            {glucoseLogs.length > 0 && (
