                                        <option value="fasting">Fasting</option>
                                        <option value="post_prandial">PP (2hr)</option>
                                        <option value="random">Random</option>
                                    </select>
                                    <input type="number" placeholder="mg/dL" className="w-1/3 px-3 py-2 rounded-lg border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white" value={newGlucose.value} onChange={e => setNewGlucose({...newGlucose, value: e.target.value})} />
