                                        <div key={log.id} className="p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30">
                                            <div className="flex justify-between items-center"><div><span className="font-bold text-lg text-gray-800 dark:text-white">{log.value}</span><span className="text-xs text-gray-500 ml-1">mg/dL</span></div><span className={`text-xs font-bold ${status.color}`}>{status.label}</span></div>
                                            <div className="flex justify-between mt-1 text-xs text-gray-400"><span className="capitalize">{log.type.replace('_', ' ')}</span><span>{new Date(log.date).toLocaleDateString()}</span></div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                    <div className="grid md:grid-cols-1 gap-6">
                        {renderLabInput("Thyroid (TSH)", "tsh", tshLogs, "mIU/L", calculations.trimester === 1 ? LAB_THRESHOLDS.tsh.pregnant_t1 : LAB_THRESHOLDS.tsh.pregnant_t2_t3)}
                        {renderLabInput("Hemoglobin (Hb)", "hb", hbLogs, "g/dL", LAB_THRESHOLDS.hemoglobin.pregnant)}
                        {renderLabInput("HbA1c", "hba1c", hba1cLogs, "%", LAB_THRESHOLDS.hba1c.pregnant)}
                    </div>
                    <div className="md:col-span-2 p-4 bg-yellow-50 dark:bg-yellow-900/10 rounded-xl border border-yellow-100 dark:border-yellow-900/30 flex items-start gap-3">
                        <AlertCircle className="text-yellow-600 shrink-0 mt-0.5" />
                        <div className="text-sm text-yellow-800 dark:text-yellow-300"><strong>Medical Standard Disclaimer:</strong> Thresholds are based on FOGSI (India) guidelines for GDM, Hypertension, Anemia, and Hypothyroidism. Red indicators require immediate consultation with your gynecologist.</div>
                    </div>
                </div>
            )
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './Button';
import { Contraction } from '../types';
import { Play, Square, RotateCcw, AlertCircle, Clock, Activity } from 'lucide-react';
import { StorageService } from '../services/storage';

export const ContractionTimer: React.FC = () => {
  const [contractions, setContractions] = useState<Contraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [timer, setTimer] = useState(0);

  useEffect(() => {
    const saved = StorageService.getItem('bloom_contractions');
    if (saved) {
      setContractions(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (activeId) {
      interval = window.setInterval(() => {
        setTimer(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [activeId]);

  const toggleTimer = () => {
    if (activeId) {
      const updated = contractions.map(c => {
        if (c.id === activeId) {
          return {
            ...c,
            endTime: new Date().toISOString(),
            durationSeconds: timer
          };
        }
        return c;
      });
      setContractions(updated);
      StorageService.setItem('bloom_contractions', JSON.stringify(updated));
      setActiveId(null);
      setTimer(0);
    } else {
      const now = new Date();
      const lastContraction = contractions.length > 0 ? contractions[0] : null;
      let frequency = null;
      if (lastContraction) {
        const lastStart = new Date(lastContraction.startTime).getTime();
        const currentStart = now.getTime();
        frequency = Math.floor((currentStart - lastStart) / 1000);
      }
      const newContraction: Contraction = {
        id: Date.now().toString(),
        startTime: now.toISOString(),
        endTime: null,
        durationSeconds: 0,
        frequencySeconds: frequency
      };
      const updated = [newContraction, ...contractions];
      setContractions(updated);
      setActiveId(newContraction.id);
      setTimer(0);
    }
  };

  const resetAll = () => {
    if (confirm("Delete all contraction history?")) {
      setContractions([]);
      StorageService.removeItem('bloom_contractions');
      setActiveId(null);
      setTimer(0);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const formatDuration = (seconds: number) => {
     if (seconds < 60) return `${seconds}s`;
     return `${Math.floor(seconds/60)}m ${seconds%60}s`;
  };

  const formatFreq = (seconds: number | null) => {
     if (!seconds) return '-';
     const mins = Math.floor(seconds / 60);
     return `${mins} min`;
  };

  const analyzeLabor = () => {
      if (contractions.length < 3) return null;
      const recent = contractions.slice(0, 5); 
      const avgFreq = recent.reduce((acc, c) => acc + (c.frequencySeconds || 0), 0) / (recent.length - 1); 
      const avgDur = recent.reduce((acc, c) => acc + c.durationSeconds, 0) / recent.length;
      if (avgFreq > 0 && avgFreq <= 360 && avgDur >= 45) {
          return { status: 'hospital', message: "Hospital Alert! Contractions are consistent (~5 min apart). Call your doctor." };
      }
      if (avgFreq > 0 && avgFreq <= 600) {
          return { status: 'prepare', message: "Labor may be progressing. Pack your bags." };
      }
      return { status: 'early', message: "Early labor or Braxton Hicks. Keep monitoring." };
  };

  const alert = analyzeLabor();

  return (
    <div className="space-y-6 animate-fade-in">
      <div className={`rounded-3xl p-8 text-white shadow-xl transition-colors duration-500 relative overflow-hidden ${activeId ? 'bg-green-600' : 'bg-gradient-to-br from-blue-600 to-indigo-600'}`}>
         {activeId && (<div className="absolute inset-0 bg-green-500 animate-pulse opacity-50"></div>)}
         <div className="relative z-10 flex flex-col items-center justify-center text-center">
             <h2 className="text-xl font-bold uppercase tracking-widest opacity-80 mb-2">{activeId ? "Contraction Active" : "Ready to Timer"}</h2>
             <div className="text-7xl font-mono font-bold mb-8 tabular-nums">{formatTime(timer)}</div>
             <button onClick={toggleTimer} className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg transition-transform active:scale-90 ${activeId ? 'bg-white text-green-600 hover:bg-gray-100' : 'bg-white text-indigo-600 hover:bg-gray-100'}`}>
                {activeId ? <Square size={32} fill="currentColor" /> : <Play size={36} fill="currentColor" className="ml-1" />}
             </button>
             <p className="mt-6 font-medium opacity-90">{activeId ? "Breathe... Relax your shoulders." : "Press Play when pain starts"}</p>
         </div>
      </div>
      {alert && contractions.length >= 3 && (
          <div className={`p-4 rounded-xl border flex gap-3 items-start ${alert.status === 'hospital' ? 'bg-red-100 border-red-300 text-red-800' : alert.status === 'prepare' ? 'bg-orange-100 border-orange-300 text-orange-800' : 'bg-blue-50 border-blue-200 text-blue-800'}`}>
              <AlertCircle className="shrink-0 mt-0.5" />
              <div><h4 className="font-bold">Analysis</h4><p className="text-sm">{alert.message}</p></div>
          </div>
      )}
      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
          <div className="p-4 border-b border-gray-100 dark:border-indigo-800 flex justify-between items-center"><h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2"><Activity size={20} /> History</h3>{contractions.length > 0 && <button onClick={resetAll} className="text-xs text-red-500">Reset</button>}</div>
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 dark:bg-indigo-900/30 text-gray-500 dark:text-gray-400"><tr><th className="p-4 font-bold">Start Time</th><th className="p-4 font-bold">Duration</th><th className="p-4 font-bold">Frequency</th></tr></thead>
                <tbody className="divide-y divide-gray-100 dark:divide-indigo-800">
                    {contractions.length === 0 ? (<tr><td colSpan={3} className="p-8 text-center text-gray-400">No contractions recorded.</td></tr>) : (contractions.map((c, i) => (<tr key={c.id} className={i === 0 && activeId ? "bg-green-50 dark:bg-green-900/10 animate-pulse" : ""}><td className="p-4 text-gray-800 dark:text-white">{new Date(c.startTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</td><td className="p-4 font-bold text-gray-800 dark:text-white">{c.endTime || activeId === c.id ? formatDuration(c.durationSeconds) : '...'}</td><td className="p-4 text-gray-600 dark:text-gray-300">{formatFreq(c.frequencySeconds)}</td></tr>)))}
                </tbody>
            </table>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-indigo-950/30 text-xs text-gray-500 dark:text-gray-400"><p><strong>Frequency:</strong> Time from start of one contraction to the start of the next.</p><p><strong>5-1-1 Rule:</strong> Contractions 5 mins apart, lasting 1 min, for 1 hour = Call Doctor.</p></div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './Button';
import { KickSession } from '../types';
import { Play, Square, RotateCcw, History, Footprints } from 'lucide-react';
import { StorageService } from '../services/storage';

export const KickCounter: React.FC = () => {
  const [sessions, setSessions] = useState<KickSession[]>([]);
  const [currentSession, setCurrentSession] = useState<KickSession | null>(null);
  const [elapsedTime, setElapsedTime] = useState(0);

  useEffect(() => {
    const saved = StorageService.getItem('bloom_kicks');
    if (saved) {
      setSessions(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (currentSession && !currentSession.endTime) {
      interval = window.setInterval(() => {
        setElapsedTime(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [currentSession]);

  const formatTime = (seconds: number) => {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${hrs > 0 ? `${hrs}h ` : ''}${mins}m ${secs}s`;
  };

  const handleKick = () => {
    if (navigator.vibrate) navigator.vibrate(50); 

    if (!currentSession) {
      const newSession: KickSession = {
        id: Date.now().toString(),
        date: new Date().toISOString().split('T')[0],
        startTime: new Date().toISOString(),
        endTime: null,
        count: 1,
        durationSeconds: 0
      };
      setCurrentSession(newSession);
      setElapsedTime(0);
    } else {
      const updated = { ...currentSession, count: currentSession.count + 1 };
      if (updated.count === 10) {
        finishSession(updated);
      } else {
        setCurrentSession(updated);
      }
    }
  };

  const finishSession = (sessionData: KickSession = currentSession!) => {
    const finalSession = {
      ...sessionData,
      endTime: new Date().toISOString(),
      durationSeconds: elapsedTime
    };

    const newHistory = [finalSession, ...sessions];
    setSessions(newHistory);
    StorageService.setItem('bloom_kicks', JSON.stringify(newHistory));
    setCurrentSession(null);
    setElapsedTime(0);
  };

  const cancelSession = () => {
    setCurrentSession(null);
    setElapsedTime(0);
  };

  const clearHistory = () => {
    if(confirm("Clear all kick history?")) {
        setSessions([]);
        StorageService.removeItem('bloom_kicks');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-gradient-to-br from-pink-500 to-rose-600 rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-40 h-40 bg-white opacity-10 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10 text-center">
            <h2 className="text-2xl font-bold mb-2 flex items-center justify-center gap-2"><Footprints fill="currentColor" /> Fetal Movement Tracker</h2>
            <p className="opacity-90 mb-6">Standard: Reach 10 kicks within 2 hours.</p>
            <div className="mb-8">
                <div className="text-7xl font-bold mb-2">{currentSession ? currentSession.count : 0}<span className="text-2xl opacity-60">/10</span></div>
                <div className="text-xl font-mono opacity-80 bg-black/10 inline-block px-4 py-1 rounded-full">{formatTime(elapsedTime)}</div>
            </div>
            <button onClick={handleKick} className="w-full max-w-xs mx-auto aspect-square rounded-full bg-white text-pink-600 shadow-lg flex flex-col items-center justify-center gap-2 transition-transform active:scale-95 hover:shadow-xl hover:bg-pink-50">
                <Footprints size={64} fill="currentColor" />
                <span className="text-xl font-bold uppercase tracking-wider">Tap to Log Kick</span>
            </button>
            {currentSession && (
                <div className="flex gap-4 justify-center mt-8">
                    <button onClick={() => finishSession()} className="px-6 py-2 bg-white/20 hover:bg-white/30 rounded-xl backdrop-blur-sm font-medium transition-colors">Finish Early</button>
                    <button onClick={cancelSession} className="px-6 py-2 bg-red-500/20 hover:bg-red-500/30 rounded-xl backdrop-blur-sm font-medium transition-colors">Cancel</button>
                </div>
            )}
        </div>
      </div>
      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 p-6">
          <div className="flex items-center justify-between mb-4"><h3 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2"><History size={20} /> History</h3>{sessions.length > 0 && (<button onClick={clearHistory} className="text-xs text-red-500 hover:underline">Clear All</button>)}</div>
          <div className="space-y-3 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
              {sessions.length === 0 ? (<div className="text-center text-gray-400 py-8">No sessions recorded yet.</div>) : (sessions.map(s => (<div key={s.id} className="flex items-center justify-between p-4 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30"><div><p className="font-bold text-gray-800 dark:text-white">{new Date(s.startTime).toLocaleDateString()}</p><p className="text-xs text-gray-500 dark:text-gray-400">{new Date(s.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p></div><div className="text-right"><p className="font-bold text-pink-600 text-lg">{s.count} Kicks</p><p className="text-xs text-gray-500 dark:text-gray-400">in {formatTime(s.durationSeconds)}</p></div></div>)))}
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { PregnancyCalculations, WeeklyInfo, UserSettings, Medicine } from '../types';
import { WEEKLY_DATA, FALLBACK_WEEKLY_INFO, SCAN_SCHEDULE, LAB_SCHEDULE, MATERNAL_VACCINES, MATERNAL_AGE_RISKS, OBSTETRIC_HISTORY_RISKS, TIP_LIBRARY } from '../constants';
import { getPregnancyAdvice } from '../services/geminiService';
import { Button } from './Button';
import { Info, Baby, AlertCircle, Bell, RotateCcw, Syringe, Sparkles, FlaskConical, ShieldAlert, Key, CheckCircle2, Lightbulb, Pill, Ruler, ChevronLeft, ChevronRight } from 'lucide-react';
import { StorageService } from '../services/storage';

interface Props {
  calculations: PregnancyCalculations;
  settings: UserSettings;
}

export const Dashboard: React.FC<Props> = ({ calculations, settings }) => {
  const [selectedWeek, setSelectedWeek] = useState(calculations.currentWeek);
  const [todaysMedicines, setTodaysMedicines] = useState<Medicine[]>([]);

  useEffect(() => {
    setSelectedWeek(calculations.currentWeek);
  }, [calculations.currentWeek]);

  useEffect(() => {
      const isPostpartum = settings.status === 'postpartum';
      const key = isPostpartum ? 'bloom_pp_medicines' : 'bloom_medicines';
      const stored = StorageService.getItem(key);
      if (stored) {
          const parsed: Medicine[] = JSON.parse(stored);
          setTodaysMedicines(parsed.filter(m => !m.taken));
      } else {
          setTodaysMedicines([]);
      }
  }, [settings.status]);

  const displayTrimester = selectedWeek <= 13 ? 1 : selectedWeek <= 27 ? 2 : 3;
  const displayMonth = Math.ceil(selectedWeek / 4.3);
  const displayProgress = Math.min((selectedWeek / 40) * 100, 100);

  const availableWeeks = Object.keys(WEEKLY_DATA).map(Number).sort((a, b) => a - b);
  const closestWeek = availableWeeks.reduce((prev, curr) => 
    Math.abs(curr - selectedWeek) < Math.abs(prev - selectedWeek) ? curr : prev
  );

  const weekInfo: WeeklyInfo = WEEKLY_DATA[selectedWeek] || WEEKLY_DATA[closestWeek] || FALLBACK_WEEKLY_INFO;

  const relevantScans = SCAN_SCHEDULE.filter(scan => {
    return (selectedWeek >= scan.weekStart - 1 && selectedWeek <= scan.weekEnd);
  });

  const relevantLabs = LAB_SCHEDULE.filter(lab => {
      const isTime = selectedWeek >= lab.weekStart - 1 && selectedWeek <= lab.weekEnd;
      if (!isTime) return false;
      if (lab.condition) {
          if (lab.condition === 'thyroid' && !settings.comorbidities.includes('thyroid')) return false;
          if (lab.condition === 'anemia' && !settings.comorbidities.includes('anemia')) return false;
          if (lab.condition === 'rh_negative' && (!settings.maternalBloodGroup || !settings.maternalBloodGroup.includes('-'))) return false;
      }
      return true;
  });

  const vaccinationsDone = settings.vaccinationsDone || [];
  const upcomingVaccines = MATERNAL_VACCINES.filter(vax => {
    const isDone = vaccinationsDone.includes(vax.id);
    return !isDone && (selectedWeek >= vax.dueWeekStart - 2 && selectedWeek <= vax.dueWeekEnd + 4);
  });

  const selectedComorbidities = settings.comorbidities || [];

  const [question, setQuestion] = useState('');
  const [aiAnswer, setAiAnswer] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [missingKey, setMissingKey] = useState(false);

  const askAi = async () => {
    if (!question.trim()) return;
    setLoadingAi(true);
    setMissingKey(false);

    const answer = await getPregnancyAdvice(question, selectedWeek);

    if (answer === "MISSING_KEY") {
        setMissingKey(true);
        setAiAnswer(null);
    } else {
        setAiAnswer(answer);
    }

    setLoadingAi(false);
  };

  const handlePrevWeek = () => {
    if (selectedWeek > 1) setSelectedWeek(p => p - 1);
  };

  const handleNextWeek = () => {
    if (selectedWeek < 42) setSelectedWeek(p => p + 1);
  };

  const handleResetToCurrent = () => {
    setSelectedWeek(calculations.currentWeek);
  };

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);
  const minSwipeDistance = 50;

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;

    if (isLeftSwipe) handleNextWeek();
    if (isRightSwipe) handlePrevWeek();
  };

  const calculateRiskProfile = () => {
      const risks: string[] = [];
      const actions: string[] = [];
      let level: 'Low' | 'Moderate' | 'High' = 'Low';

      const age = settings.age;
      if (age) {
          if (age < 18) {
              level = 'Moderate';
              risks.push(MATERNAL_AGE_RISKS.teenage.label);
              actions.push(MATERNAL_AGE_RISKS.teenage.action);
          } else if (age > 35) {
              level = 'High';
              risks.push(MATERNAL_AGE_RISKS.advanced.label);
              actions.push(MATERNAL_AGE_RISKS.advanced.action);
          }
      }

      if (settings.heightCm && settings.prePregnancyWeight) {
          const bmi = settings.prePregnancyWeight / ((settings.heightCm / 100) ** 2);
          if (bmi > 30) {
              level = 'High';
              risks.push("Obesity (BMI > 30)");
              actions.push("High risk of GDM/HTN. Early GTT required. Monitor fetal growth.");
          } else if (bmi < 18.5) {
              level = level === 'High' ? 'High' : 'Moderate';
              risks.push("Underweight (BMI < 18.5)");
              actions.push("Risk of IUGR (Small Baby). Increase caloric intake.");
          }
      }

      if (settings.heightCm && settings.heightCm < 145) {
          level = level === 'High' ? 'High' : 'Moderate';
          risks.push("Short Stature (<145cm)");
          actions.push("Risk of Cephalo-Pelvic Disproportion (CPD). Hospital delivery mandatory.");
      }

      if (selectedComorbidities.length > 0) {
          level = 'High';
      }

      const obs = settings.obstetricHistory;
      if (obs) {
          if (obs.abortionsT1 >= 2) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.action);
          }
          if (obs.abortionsT2 >= 1) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.t2_loss.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.t2_loss.action);
          }
          if (obs.lastBabyCongenitalDefect) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.action);
          }
          if (obs.para >= 4) {
              level = 'High';
              risks.push("Grand Multipara (Para ≥ 4)");
              actions.push("High risk of PPH and Anemia. Active management of labor required.");
          }
      }

      return { level, risks, actions };
  };

  const riskProfile = calculateRiskProfile();

  const isFuture = selectedWeek > calculations.currentWeek;
  const isPast = selectedWeek < calculations.currentWeek;

  let currentTip = "";
  if (weekInfo.dailyTips && weekInfo.dailyTips.length > 0) {
      const dayIndex = selectedWeek === calculations.currentWeek 
          ? (calculations.currentDay % 7) 
          : 0; 
      currentTip = weekInfo.dailyTips[dayIndex] || weekInfo.dailyTips[0];
  } else {
      currentTip = "Stay hydrated and rest well. Listen to your body.";
  }

  const hasBiometry = weekInfo.biometry && (Object.keys(weekInfo.biometry).length > 0);

  return (
    <div className="space-y-8 animate-fade-in pb-10">
      {(isFuture || isPast) && (
        <div className="flex justify-center -mb-4 z-10 relative">
          <button onClick={handleResetToCurrent} className="flex items-center gap-2 px-4 py-2 bg-pink-100 dark:bg-pink-900/30 text-pink-700 dark:text-pink-300 rounded-full text-sm font-bold hover:bg-pink-200 transition-colors shadow-sm">
            <RotateCcw size={14} /> Back to Current Week ({calculations.currentWeek})
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="col-span-1 md:col-span-2 bg-gradient-to-br from-pink-600 to-purple-700 rounded-3xl p-6 text-white shadow-xl shadow-pink-500/20 relative overflow-hidden select-none" onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>
            <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl pointer-events-none"></div>
            <button onClick={handlePrevWeek} disabled={selectedWeek <= 1} className="absolute left-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"><ChevronLeft size={24} /></button>
            <button onClick={handleNextWeek} disabled={selectedWeek >= 42} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"><ChevronRight size={24} /></button>

            <div className="relative z-10 flex flex-col md:flex-row items-center gap-8 justify-center md:justify-start">
                <div className="relative w-40 h-40 flex-shrink-0">
                    <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                        <circle className="text-white/20 stroke-current" strokeWidth="8" cx="50" cy="50" r="40" fill="transparent"></circle>
