              </div>
              <p className="text-[10px] text-indigo-600 dark:text-indigo-400 mt-3 text-center">*Reference ranges based on Hadlock/WHO standards. Actual measurements may vary.</p>
          </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {relevantScans.length > 0 && (
