                <div className="flex-1"><h3 className="font-bold text-orange-800 dark:text-orange-200 text-sm uppercase">Scan Due</h3><p className="text-orange-700 dark:text-orange-300 text-sm font-bold">{relevantScans[0].name}</p><p className="text-xs text-orange-600 dark:text-orange-400">Weeks {relevantScans[0].weekStart}-{relevantScans[0].weekEnd}</p></div>
