          {upcomingVaccines.length > 0 && (
             <div className="bg-teal-50 dark:bg-teal-900/10 p-4 rounded-3xl border border-teal-100 dark:border-teal-900/30 flex gap-4 items-center">
                <div className="bg-teal-100 dark:bg-teal-800/30 p-3 rounded-full text-teal-600 dark:text-teal-400 shrink-0"><Syringe className="w-6 h-6" /></div>
                <div className="flex-1"><h3 className="font-bold text-teal-800 dark:text-teal-200 text-sm uppercase">Vaccine Due</h3><p className="text-teal-700 dark:text-teal-300 text-sm font-bold">{upcomingVaccines[0].name}</p><p className="text-xs text-teal-600 dark:text-teal-400">Due: Week {upcomingVaccines[0].dueWeekStart}-{upcomingVaccines[0].dueWeekEnd}</p></div>
             </div>
          )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
            <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-pink-100 dark:border-indigo-800" key={selectedWeek}>
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-gray-800 dark:text-white"><Info className="text-pink-600" /> Week {selectedWeek} Highlights</h3>
                <p className="text-gray-600 dark:text-gray-300 leading-relaxed mb-4">{weekInfo.description}</p>
