import React, { useState, useEffect } from 'react';
import { Medicine, AppMode } from '../types';
import { Pill, Plus, Trash2, Check, ShieldAlert } from 'lucide-react';
import { Button } from './Button';
import { MedicineSafety } from './MedicineSafety';
import { StorageService } from '../services/storage';

interface Props {
  currentWeek?: number;
  isPostpartum?: boolean;
  mode?: AppMode;
  comorbidities?: string[];
}

export const MedicineTracker: React.FC<Props> = ({ currentWeek = 1, isPostpartum = false, mode = 'pregnant', comorbidities }) => {
  const [activeTab, setActiveTab] = useState<'my-meds' | 'safety'>('my-meds');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [newMed, setNewMed] = useState({ name: '', time: '' });

  const STORAGE_KEY = isPostpartum ? 'bloom_pp_medicines' : 'bloom_medicines';
  const DATE_KEY = STORAGE_KEY + '_date';

  useEffect(() => {
    const loadMedicines = () => {
        const saved = StorageService.getItem(STORAGE_KEY);
        const lastDate = StorageService.getItem(DATE_KEY);
        const today = new Date().toISOString().split('T')[0];

        if (saved) {
            let parsed = JSON.parse(saved);
            if (lastDate !== today) {
                parsed = parsed.map((m: Medicine) => ({ ...m, taken: false }));
                StorageService.setItem(STORAGE_KEY, JSON.stringify(parsed));
                StorageService.setItem(DATE_KEY, today);
            }
            setMedicines(parsed);
        } else {
            const defaults: Medicine[] = isPostpartum ? [
                { id: '1', name: 'Calcium', dosage: '500mg', frequency: 'BD', time: '09:00', taken: false },
                { id: '2', name: 'Iron', dosage: '100mg', frequency: 'OD', time: '20:00', taken: false }
            ] : [
                { id: '1', name: 'Folic Acid', dosage: '5mg', frequency: 'Daily', time: '09:00', taken: false },
                { id: '2', name: 'Iron Supplement', dosage: '100mg', frequency: 'Daily', time: '20:00', taken: false }
            ];
            setMedicines(defaults);
            StorageService.setItem(STORAGE_KEY, JSON.stringify(defaults));
            StorageService.setItem(DATE_KEY, today);
        }
    };
    loadMedicines();
  }, [isPostpartum]);

  useEffect(() => {
      if (medicines.length > 0) {
          StorageService.setItem(STORAGE_KEY, JSON.stringify(medicines));
          StorageService.setItem(DATE_KEY, new Date().toISOString().split('T')[0]);
      }
  }, [medicines, STORAGE_KEY]);

  const toggleTaken = (id: string) => {
    setMedicines(prev => prev.map(m => m.id === id ? { ...m, taken: !m.taken } : m));
  };

  const addMed = () => {
    if (newMed.name && newMed.time) {
      setMedicines(prev => [...prev, {
        id: Date.now().toString(),
        name: newMed.name,
        time: newMed.time,
        dosage: 'Check label',
        frequency: 'Daily',
        taken: false
      }]);
      setNewMed({ name: '', time: '' });
    }
  };

  const removeMed = (id: string) => {
    setMedicines(prev => prev.filter(m => m.id !== id));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">
       <div className="flex gap-2 p-1 bg-gray-100 dark:bg-indigo-950/50 rounded-xl w-fit mx-auto mb-6">
          <button onClick={() => setActiveTab('my-meds')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'my-meds' ? 'bg-white dark:bg-deep-card shadow text-teal-600 dark:text-teal-400' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}>My Medicines</button>
          <button onClick={() => setActiveTab('safety')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${activeTab === 'safety' ? 'bg-white dark:bg-deep-card shadow text-bloom-DEFAULT' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}><ShieldAlert size={16} /> {isPostpartum ? 'Lactation Safety' : 'Safety Guide'}</button>
       </div>

       {activeTab === 'my-meds' ? (
         <>
          <div className="bg-gradient-to-r from-teal-500 to-emerald-500 rounded-3xl p-8 text-white shadow-lg">
              <h2 className="text-2xl font-bold mb-2">Medicine Cabinet</h2>
              <p className="opacity-90">Keep track of your supplements and prescriptions. Compliance is key for a healthy {isPostpartum ? 'recovery' : 'pregnancy'}.</p>
          </div>

          <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
              <div className="p-6 border-b border-gray-100 dark:border-indigo-800"><h3 className="font-bold text-gray-800 dark:text-white text-lg">Daily Checklist</h3></div>
              <div className="divide-y divide-gray-100 dark:divide-indigo-800">
                {medicines.map(med => (
                  <div key={med.id} className={`p-4 flex items-center justify-between transition-colors ${med.taken ? 'bg-green-50/50 dark:bg-green-900/10' : 'hover:bg-gray-50 dark:hover:bg-indigo-900/20'}`}>
                      <div className="flex items-center gap-4">
                        <button onClick={() => toggleTaken(med.id)} className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${med.taken ? 'bg-green-500 border-green-500 text-white' : 'border-gray-300 dark:border-gray-600 text-transparent hover:border-green-500'}`}><Check size={16} /></button>
                        <div><p className={`font-medium text-lg ${med.taken ? 'text-gray-400 line-through' : 'text-gray-800 dark:text-white'}`}>{med.name}</p><p className="text-sm text-gray-500 dark:text-gray-400">{med.time} • {med.dosage}</p></div>
                      </div>
                      <button onClick={() => removeMed(med.id)} className="text-gray-400 hover:text-red-500 p-2"><Trash2 size={18} /></button>
                  </div>
                ))}
                {medicines.length === 0 && (<div className="p-8 text-center text-gray-500">No medicines added yet.</div>)}
              </div>
              <div className="p-6 bg-gray-50 dark:bg-indigo-950/30">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full"><label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Medicine Name</label><input type="text" value={newMed.name} onChange={(e) => setNewMed({...newMed, name: e.target.value})} className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900" placeholder="e.g. Calcium" /></div>
                    <div className="w-full md:w-40"><label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Time</label><input type="time" value={newMed.time} onChange={(e) => setNewMed({...newMed, time: e.target.value})} className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900" /></div>
                    <Button onClick={addMed} className="w-full md:w-auto bg-teal-500 hover:bg-teal-600 hover:shadow-teal-500/30"><Plus size={20} /> Add</Button>
                </div>
              </div>
          </div>
         </>
       ) : (
         <MedicineSafety currentWeek={currentWeek} isPostpartum={isPostpartum} mode={mode} comorbidities={comorbidities} />
       )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserSettings } from '../types';
import { Button } from './Button';
import { Baby, Clock, Activity, TrendingUp, Square, RotateCcw, CheckSquare, Square as SquareIcon, Star, Lightbulb, BookOpen, Trash2, History, AlertTriangle, ShieldAlert, Info } from 'lucide-react';
import { DETAILED_MILESTONES, TIP_LIBRARY, DID_YOU_KNOW_DATA, DEVELOPMENTAL_RED_FLAGS } from '../constants';
import { StorageService } from '../services/storage';

interface Props {
  settings: UserSettings;
}

interface NursingLog {
  id: string;
  startTime: string;
  endTime: string;
  duration: number;
  side: 'Left' | 'Right';
}

export const PostpartumDashboard: React.FC<Props> = ({ settings }) => {
  const [babyAge, setBabyAge] = useState<{weeks: number, days: number, totalMonths: number}>({ weeks: 0, days: 0, totalMonths: 0 });
  const [timer, setTimer] = useState(0);
  const [isActive, setIsActive] = useState(false);
  const [activeSide, setActiveSide] = useState<'Left' | 'Right' | null>(null);
  const [nursingLogs, setNursingLogs] = useState<NursingLog[]>([]);
  const [completedMilestones, setCompletedMilestones] = useState<string[]>([]);

  const dayOfYear = Math.floor((new Date().getTime() - new Date(new Date().getFullYear(), 0, 0).getTime()) / 1000 / 60 / 60 / 24);
  const dailyTip = TIP_LIBRARY.postpartum[dayOfYear % TIP_LIBRARY.postpartum.length];
  const didYouKnow = DID_YOU_KNOW_DATA.postpartum[dayOfYear % DID_YOU_KNOW_DATA.postpartum.length];

  useEffect(() => {
    if (settings.birthDate) {
      const birth = new Date(settings.birthDate);
      const now = new Date();
      const diffTime = Math.abs(now.getTime() - birth.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      const diffMonths = (now.getFullYear() - birth.getFullYear()) * 12 + (now.getMonth() - birth.getMonth());
      const adjustedMonths = now.getDate() < birth.getDate() ? diffMonths - 1 : diffMonths;

      setBabyAge({
        weeks: Math.floor(diffDays / 7),
        days: diffDays % 7,
        totalMonths: Math.max(0, adjustedMonths)
      });
    }

    const savedMilestones = StorageService.getItem('bloom_milestones');
    if (savedMilestones) {
        setCompletedMilestones(JSON.parse(savedMilestones));
    }

    const savedLogs = StorageService.getItem('bloom_nursing_logs');
    if (savedLogs) {
        setNursingLogs(JSON.parse(savedLogs));
    }
  }, [settings.birthDate]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive) {
      interval = window.setInterval(() => {
        setTimer((prev) => prev + 1);
      }, 1000);
    } else if (!isActive && timer !== 0) {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isActive, timer]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const handleStart = (side: 'Left' | 'Right') => {
    if (activeSide !== side) {
      setTimer(0);
    }
    setActiveSide(side);
    setIsActive(true);
  };

  const handleStop = () => {
    setIsActive(false);
    if (activeSide && timer > 0) {
        const now = new Date();
        const start = new Date(now.getTime() - timer * 1000);

        const newLog: NursingLog = {
            id: Date.now().toString(),
            startTime: start.toISOString(),
            endTime: now.toISOString(),
            duration: timer,
            side: activeSide
        };

        const updatedLogs = [newLog, ...nursingLogs];
        setNursingLogs(updatedLogs);
        StorageService.setItem('bloom_nursing_logs', JSON.stringify(updatedLogs));
        setTimer(0);
        setActiveSide(null);
    }
  };

  const deleteNursingLog = (id: string) => {
      if(confirm("Delete this log?")) {
          const updated = nursingLogs.filter(l => l.id !== id);
          setNursingLogs(updated);
          StorageService.setItem('bloom_nursing_logs', JSON.stringify(updated));
      }
  };

  const toggleMilestone = (id: string) => {
      let updated;
      if (completedMilestones.includes(id)) {
          updated = completedMilestones.filter(m => m !== id);
      } else {
          updated = [...completedMilestones, id];
      }
      setCompletedMilestones(updated);
      StorageService.setItem('bloom_milestones', JSON.stringify(updated));
  };

  const activeRedFlags = DEVELOPMENTAL_RED_FLAGS.filter(flag => {
      if (babyAge.totalMonths >= flag.limitMonth) {
          return !completedMilestones.includes(flag.linkedMilestoneId);
      }
      return false;
  });

  return (
    <div className="space-y-8 animate-fade-in pb-10">
      <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
         <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>
         <div className="relative z-10 flex flex-col md:flex-row items-center gap-6">
            <div className="w-24 h-24 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-md"><Baby size={48} /></div>
            <div className="text-center md:text-left"><h2 className="text-3xl font-bold">Welcome, {settings.babyName || "Little One"}!</h2><div className="mt-2 text-xl font-medium opacity-90">{babyAge.weeks} Weeks, {babyAge.days} Days Old ({babyAge.totalMonths} months)</div><p className="text-sm opacity-75 mt-1">Focus: Recovery & Bonding (The 4th Trimester)</p></div>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30"><h4 className="font-bold text-blue-800 dark:text-blue-300 mb-2 flex items-center gap-2"><Lightbulb size={20} /> Daily Recovery Tip</h4><p className="text-sm text-blue-700 dark:text-blue-400 leading-relaxed">{dailyTip}</p></div>
          <div className="bg-purple-50 dark:bg-purple-900/10 p-6 rounded-3xl border border-purple-100 dark:border-purple-900/30"><h4 className="font-bold text-purple-800 dark:text-purple-300 mb-2 flex items-center gap-2"><BookOpen size={20} /> Did You Know?</h4><p className="text-sm font-bold text-purple-700 dark:text-purple-400 mb-1">{didYouKnow.title}</p><p className="text-xs text-purple-600 dark:text-purple-500 leading-relaxed">{didYouKnow.text}</p></div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
         <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-pink-100 dark:border-indigo-800 flex flex-col h-full">
            <h3 className="text-xl font-bold mb-4 text-gray-800 dark:text-white flex items-center gap-2"><Clock className="text-pink-500" /> Nursing Timer</h3>
            <div className="flex flex-col items-center justify-center py-4">
                <div className="text-5xl font-mono font-bold text-gray-700 dark:text-gray-200 mb-6 tracking-wider">{formatTime(timer)}</div>
                <div className="flex gap-4 w-full">
                    <button onClick={() => handleStart('Left')} disabled={isActive && activeSide === 'Right'} className={`flex-1 py-4 rounded-xl font-bold text-lg transition-all ${isActive && activeSide === 'Left' ? 'bg-pink-600 text-white shadow-lg ring-4 ring-pink-200' : 'bg-pink-50 dark:bg-pink-900/20 text-pink-700 dark:text-pink-300 hover:bg-pink-100'}`}>Left</button>
                    <button onClick={() => handleStart('Right')} disabled={isActive && activeSide === 'Left'} className={`flex-1 py-4 rounded-xl font-bold text-lg transition-all ${isActive && activeSide === 'Right' ? 'bg-pink-600 text-white shadow-lg ring-4 ring-pink-200' : 'bg-pink-50 dark:bg-pink-900/20 text-pink-700 dark:text-pink-300 hover:bg-pink-100'}`}>Right</button>
                </div>
                <div className="flex gap-4 mt-4 w-full">
                    {isActive ? (<Button variant="danger" onClick={handleStop} className="w-full"><Square size={20} fill="currentColor" /> Stop & Log</Button>) : (<Button variant="secondary" onClick={() => {setTimer(0); setActiveSide(null);}} disabled={timer === 0} className="w-full"><RotateCcw size={20} /> Reset</Button>)}
                </div>
            </div>
            <div className="mt-6 pt-6 border-t border-gray-100 dark:border-indigo-800 flex-1">
                <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-3 flex items-center gap-2 text-sm uppercase"><History size={16} /> Recent Logs</h4>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                    {nursingLogs.length === 0 ? (<p className="text-xs text-gray-400 text-center py-4">No sessions logged yet.</p>) : (nursingLogs.map(log => (<div key={log.id} className="flex justify-between items-center p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30"><div><div className="flex items-center gap-2"><span className={`text-xs font-bold px-2 py-0.5 rounded ${log.side === 'Left' ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>{log.side}</span><span className="text-sm font-bold text-gray-800 dark:text-white">{formatTime(log.duration)}</span></div><p className="text-[10px] text-gray-500 mt-1">{new Date(log.startTime).toLocaleString([], {month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'})}</p></div><button onClick={() => deleteNursingLog(log.id)} className="text-gray-400 hover:text-red-500"><Trash2 size={16} /></button></div>)))}
                </div>
            </div>
         </div>

         <div className="space-y-6">
            <div className="bg-green-50 dark:bg-green-900/10 p-6 rounded-3xl border border-green-100 dark:border-green-900/30">
                <h3 className="font-bold text-green-800 dark:text-green-300 flex items-center gap-2 mb-2"><Activity size={20} /> Mom's Vitals Check</h3>
                <ul className="space-y-2 text-sm text-green-700 dark:text-green-400"><li>• <strong>Hydration:</strong> Critical for milk supply. Drink 3-4L water.</li><li>• <strong>Rest:</strong> Sleep when the baby sleeps (easier said than done!).</li><li>• <strong>Iron/Calcium:</strong> Continue supplements for 3-6 months.</li><li>• <strong>Lochia:</strong> Bleeding may last 4-6 weeks. Watch for clots.</li></ul>
            </div>
            <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30">
                 <h3 className="font-bold text-blue-800 dark:text-blue-300 flex items-center gap-2 mb-2"><TrendingUp size={20} /> Growth Monitoring</h3>
                 <p className="text-sm text-blue-700 dark:text-blue-400 mb-2">Ensure you are tracking your baby's weight, length, and head circumference on the standard <strong>WHO/IAP Growth Charts</strong> (available in your Mamta Card).</p>
                 <div className="text-xs font-bold text-blue-600 uppercase">Next Checkup: {babyAge.weeks + 2} Weeks</div>
            </div>
         </div>
      </div>

      {activeRedFlags.length > 0 && (
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 p-6 rounded-3xl animate-pulse-slow">
              <h3 className="text-xl font-bold text-red-700 dark:text-red-400 flex items-center gap-2 mb-3"><ShieldAlert size={24} /> Developmental Red Flags</h3>
              <p className="text-sm text-gray-700 dark:text-gray-300 mb-4 bg-white/50 dark:bg-black/20 p-3 rounded-xl">Based on your baby's age ({babyAge.totalMonths} months), the following milestones should typically be achieved. Please consult a pediatrician if these persist.</p>
              <div className="space-y-3">
                  {activeRedFlags.map((flag, idx) => (
                      <div key={idx} className="bg-white dark:bg-deep-card p-4 rounded-xl border border-red-100 dark:border-red-900/50 shadow-sm"><p className="font-bold text-red-600 dark:text-red-400 text-sm flex items-center gap-2"><AlertTriangle size={16}/> {flag.condition}</p><p className="text-xs text-gray-500 mt-1"><strong>Suggests possible:</strong> {flag.suggests}</p><p className="text-xs text-gray-400 italic mt-1">Expected by {flag.limitMonth} months</p></div>
                  ))}
              </div>
          </div>
      )}

      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
         <div className="bg-gradient-to-r from-yellow-500 to-orange-500 p-6 text-white"><h3 className="text-xl font-bold flex items-center gap-2"><Star size={24} fill="currentColor" /> Developmental Milestones</h3><p className="text-sm opacity-90 mt-1">Checklist based on Indian Academy of Pediatrics (IAP) Guidelines</p></div>
         <div className="p-6 grid grid-cols-1 lg:grid-cols-2 gap-8">
             {DETAILED_MILESTONES.map((domain, index) => (
                 <div key={index} className="space-y-3">
                     <h4 className="font-bold text-gray-800 dark:text-white border-b border-gray-200 dark:border-indigo-700 pb-2 mb-3 text-lg flex items-center gap-2"><span className="w-2 h-6 bg-yellow-500 rounded-full inline-block"></span>{domain.category}</h4>
                     <ul className="space-y-2">
                         {domain.items.map((milestone) => {
                             const isChecked = completedMilestones.includes(milestone.id);
                             return (
                                 <li key={milestone.id} className={`flex items-start gap-3 p-2 rounded-lg transition-colors ${isChecked ? 'bg-green-50 dark:bg-green-900/10' : 'hover:bg-gray-50 dark:hover:bg-indigo-900/20'}`}>
                                     <button onClick={() => toggleMilestone(milestone.id)} className={`mt-0.5 shrink-0 transition-colors ${isChecked ? 'text-green-500' : 'text-gray-300 hover:text-green-400'}`}>{isChecked ? <CheckSquare size={20} /> : <SquareIcon size={20} />}</button>
                                     <div className="flex-1"><p className={`text-sm font-medium ${isChecked ? 'text-gray-500 line-through' : 'text-gray-800 dark:text-gray-200'}`}>{milestone.milestone}</p><p className="text-xs text-gray-500 dark:text-gray-400 font-medium mt-0.5 bg-gray-100 dark:bg-indigo-900/50 inline-block px-2 py-0.5 rounded">Target: {milestone.age}</p></div>
                                 </li>
                             );
                         })}
                     </ul>
                 </div>
             ))}
         </div>
         <div className="px-6 pb-6 text-xs text-gray-500 dark:text-gray-400 italic border-t border-gray-100 dark:border-indigo-800 pt-4 mt-2"><p className="font-bold flex items-center gap-1 mb-1"><Info size={14}/> Medical Disclaimer:</p>Milestone ages are approximate. Every child develops at their own pace. Minor delays can be normal. If delays are significant, involve multiple areas, or there is loss of previously attained skills, consult a pediatrician early.</div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserSettings, PregnancyCalculations, TabView, ProfileMeta, Medicine } from './types';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { PostpartumDashboard } from './components/PostpartumDashboard';
import { PrePregnancyDashboard } from './components/PrePregnancyDashboard';
import { Timeline } from './components/Timeline';
import { ReportAnalyzer } from './components/ReportAnalyzer';
import { MedicineTracker } from './components/MedicineTracker';
import { Profile } from './components/Profile';
import { DietPlan } from './components/DietPlan';
import { VaccinationTracker } from './components/VaccinationTracker';
import { ToolsHub } from './components/ToolsHub';
import { HealthTracker } from './components/HealthTracker';
import { MalePartnerHealth } from './components/MalePartnerHealth';
import { Login } from './components/Login';
import { LayoutDashboard, Calendar, FileText, Pill, Moon, Sun, Settings, User, Utensils, Syringe, Baby, Wrench, HeartPulse, LogOut, Users, PlusCircle } from 'lucide-react';
import { supabase } from './services/supabase';
import { StorageService } from './services/storage';

// Keys that store profile-specific data which need to be swapped on profile switch
const PROFILE_SPECIFIC_KEYS = [
  'bloom_kicks',
  'bloom_contractions',
  'bloom_milestones',
  'bloom_weight_logs',
  'bloom_pp_weight_logs',
  'bloom_bp_logs',
  'bloom_pp_bp_logs',
  'bloom_glucose_logs',
  'bloom_pp_glucose_logs',
  'bloom_baby_growth',
  'bloom_tsh_logs', 'bloom_pp_tsh_logs',
  'bloom_hb_logs', 'bloom_pp_hb_logs',
  'bloom_hba1c_logs', 'bloom_pp_hba1c_logs',
  'bloom_medicines', 'bloom_pp_medicines',
  'bloom_nursing_logs'
];

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [session, setSession] = useState<any>(null);
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [activeTab, setActiveTab] = useState<TabView>(TabView.DASHBOARD);
  const [loading, setLoading] = useState(true);

  // Profile Management State
  const [profiles, setProfiles] = useState<ProfileMeta[]>([]);

  // Auth & Data Loading Logic
  useEffect(() => {
    // 1. Check active session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) {
          setIsAuthenticated(true);
          // Load data from Supabase
          StorageService.syncFromRemote().then(() => {
              loadLocalData();
              setLoading(false);
          });
      } else {
          setLoading(false);
      }
    });

    // 2. Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) {
          setIsAuthenticated(true);
          // If login just happened, sync might be needed
          StorageService.syncFromRemote().then(() => loadLocalData());
      } else {
          setIsAuthenticated(false);
          setSettings(null);
          // Clear local storage on logout to ensure data isolation
          StorageService.clear();
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const loadLocalData = () => {
    try {
      const savedSettings = StorageService.getItem('bloom_settings');
      const savedProfiles = StorageService.getItem('bloom_all_profiles');

      if (savedSettings) {
        const parsed = JSON.parse(savedSettings);

        // Default field migrations
        if (!parsed.id) parsed.id = 'default_profile_' + Date.now();
        if (!parsed.status) parsed.status = parsed.isPostpartum ? 'postpartum' : 'pregnant';
        if (!parsed.comorbidities) parsed.comorbidities = [];
        if (!parsed.dietaryPreference) parsed.dietaryPreference = 'vegetarian';
        if (parsed.lactoseIntolerant === undefined) parsed.lactoseIntolerant = false;
        if (!parsed.vaccinationsDone) parsed.vaccinationsDone = [];
        if (!parsed.preConceptionChecklist) parsed.preConceptionChecklist = [];
        if (!parsed.periodLog) parsed.periodLog = [];
        if (parsed.pregnancyLmp === undefined) parsed.pregnancyLmp = null;
        if (!parsed.maternalBloodGroup) parsed.maternalBloodGroup = '';
        if (!parsed.obstetricHistory) {
            parsed.obstetricHistory = { gravida: 1, para: 0, abortions: 0, abortionsT1: 0, abortionsT2: 0, living: 0, lastBabyCongenitalDefect: false };
        }
        if (parsed.age === undefined) parsed.age = 0; 

        setSettings(parsed);

        if (savedProfiles) {
            setProfiles(JSON.parse(savedProfiles));
        } else {
            const initialProfile: ProfileMeta = {
                id: parsed.id, name: parsed.name, status: parsed.status, babyName: parsed.babyName, babyGender: parsed.babyGender, birthDate: parsed.birthDate, lastActive: new Date().toISOString()
            };
            setProfiles([initialProfile]);
            StorageService.setItem('bloom_all_profiles', JSON.stringify([initialProfile]));
        }
      }
    } catch (e) {
      console.error("Data loading error", e);
      // Fallback to prevent crash
      StorageService.clear();
    }
  };

  // Request Notification Permission on Mount
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Profile Switching Logic ---

  const handleSwitchProfile = (targetProfileId: string) => {
      if (!settings || settings.id === targetProfileId) return;

      // 1. Snapshot Current Profile Data
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = StorageService.getItem(key);
          if (data) {
              StorageService.setItem(`${key}_${settings.id}`, data);
          } else {
              StorageService.removeItem(`${key}_${settings.id}`);
          }
      });
      StorageService.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Hydrate Target Profile Data
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const savedData = StorageService.getItem(`${key}_${targetProfileId}`);
          if (savedData) {
              StorageService.setItem(key, savedData);
          } else {
              StorageService.removeItem(key);
          }
      });

      // 3. Load Target Settings
      const targetSettingsRaw = StorageService.getItem(`bloom_settings_${targetProfileId}`);
      if (targetSettingsRaw) {
          const targetSettings = JSON.parse(targetSettingsRaw);
          setSettings(targetSettings);
          StorageService.setItem('bloom_settings', targetSettingsRaw);

          const updatedProfiles = profiles.map(p => 
              p.id === targetProfileId ? { ...p, lastActive: new Date().toISOString() } : p
          );
          setProfiles(updatedProfiles);
          StorageService.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

          window.location.reload(); 
      }
  };

  const handleAddProfile = () => {
      if (!settings) return;

      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = StorageService.getItem(key);
          if (data) StorageService.setItem(`${key}_${settings.id}`, data);
          else StorageService.removeItem(`${key}_${settings.id}`);
      });
      StorageService.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      const newId = `profile_${Date.now()}`;
      const newSettings: UserSettings = {
          id: newId,
          name: settings.name,
          status: 'planning',
          lmp: null,
          cycleLength: settings.cycleLength,
          heightCm: settings.heightCm,
          prePregnancyWeight: settings.prePregnancyWeight,
          maternalBloodGroup: settings.maternalBloodGroup,
          paternalBloodGroup: settings.paternalBloodGroup,
          paternalHeightCm: settings.paternalHeightCm,
          obstetricHistory: settings.obstetricHistory,
          comorbidities: settings.comorbidities,
          dietaryPreference: settings.dietaryPreference,
          lactoseIntolerant: settings.lactoseIntolerant,
          age: settings.age,
          periodLog: [],
          vaccinationsDone: [],
          isPostpartum: false,
          preConceptionChecklist: []
      };

      PROFILE_SPECIFIC_KEYS.forEach(key => StorageService.removeItem(key));

      setSettings(newSettings);
      StorageService.setItem('bloom_settings', JSON.stringify(newSettings));

      const newProfileMeta: ProfileMeta = {
          id: newId, name: newSettings.name, status: 'planning', babyName: undefined, lastActive: new Date().toISOString()
      };

      const updatedProfiles = [...profiles, newProfileMeta];
      setProfiles(updatedProfiles);
      StorageService.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

      window.location.reload();
  };

  const calculations: PregnancyCalculations | null = useMemo(() => {
    if (!settings || !settings.lmp) return null;

    const lmpDate = new Date(settings.lmp);
    if (isNaN(lmpDate.getTime())) return null;

    const now = new Date();
    const diffTime = Math.abs(now.getTime() - lmpDate.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    const cycleAdjustment = (settings.cycleLength || 28) - 28;
    const edd = new Date(lmpDate);
    edd.setDate(edd.getDate() + 280 + cycleAdjustment);

    const weeks = Math.floor(diffDays / 7);
    const days = diffDays % 7;

    let trimester: 1 | 2 | 3 = 1;
    if (weeks > 13) trimester = 2;
    if (weeks > 27) trimester = 3;

    return {
      edd,
      currentWeek: weeks === 0 ? 1 : weeks,
      currentDay: days,
      totalDays: diffDays,
      trimester,
      month: Math.ceil(weeks / 4.3),
      progressPercent: Math.min((diffDays / 280) * 100, 100)
    };
  }, [settings]);

  const isPostpartum = settings?.status === 'postpartum';
  const isPlanning = settings?.status === 'planning';

  // Theme Logic
  let themeColor = 'text-pink-600';
  let activeBg = 'bg-pink-600 text-white shadow-pink-500/30';
  let bgGradient = 'bg-gradient-to-r from-pink-600 to-purple-600';
  let badgeColor = 'bg-pink-100 text-pink-600';

  if (isPlanning) {
      themeColor = 'text-teal-600';
      activeBg = 'bg-teal-600 text-white shadow-teal-500/30';
      bgGradient = 'bg-gradient-to-r from-teal-500 to-emerald-600';
      badgeColor = 'bg-teal-100 text-teal-600';
  } else if (isPostpartum) {
      if (settings?.babyGender === 'boy') {
          themeColor = 'text-blue-600';
          activeBg = 'bg-blue-600 text-white shadow-blue-500/30';
          bgGradient = 'bg-gradient-to-r from-blue-600 to-cyan-600';
          badgeColor = 'bg-blue-100 text-blue-600';
      } else {
          themeColor = 'text-rose-500';
          activeBg = 'bg-rose-500 text-white shadow-rose-500/30';
          bgGradient = 'bg-gradient-to-r from-rose-400 to-pink-500';
          badgeColor = 'bg-rose-100 text-rose-600';
      }
  }

  const getBabyAgeInWeeks = () => {
    if (!settings?.birthDate) return 0;
    const birth = new Date(settings.birthDate);
    const now = new Date();
    const diff = Math.abs(now.getTime() - birth.getTime());
    return Math.floor(diff / (1000 * 60 * 60 * 24 * 7));
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setActiveTab(TabView.DASHBOARD);
  };

  const handleOnboardingComplete = (data: UserSettings) => {
    if (!data.id) data.id = 'profile_' + Date.now();
    if (data.lmp) {
        data.periodLog = [data.lmp];
        data.pregnancyLmp = data.status === 'pregnant' ? data.lmp : null;
    }
    if (!data.obstetricHistory) {
        data.obstetricHistory = { gravida: 1, para: 0, abortions: 0, abortionsT1: 0, abortionsT2: 0, living: 0, lastBabyCongenitalDefect: false };
    }
    if (data.age === undefined) data.age = 0;

    setSettings(data);
    StorageService.setItem('bloom_settings', JSON.stringify(data));

    const meta: ProfileMeta = {
        id: data.id, name: data.name, status: data.status, babyName: data.babyName, babyGender: data.babyGender, birthDate: data.birthDate, lastActive: new Date().toISOString()
    };
    setProfiles([meta]);
    StorageService.setItem('bloom_all_profiles', JSON.stringify([meta]));
  };

  const handleUpdateProfile = (data: UserSettings) => {
    setSettings(data);
    StorageService.setItem('bloom_settings', JSON.stringify(data));

    const updatedProfiles = profiles.map(p => 
        p.id === data.id ? { 
            ...p, name: data.name, status: data.status, babyName: data.babyName, babyGender: data.babyGender, birthDate: data.birthDate
        } : p
    );
    setProfiles(updatedProfiles);
    StorageService.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));
  };

  const handleVaccineUpdate = (vaxId: string) => {
    if (!settings) return;
    const currentDone = settings.vaccinationsDone || [];
    let newDone;
    if (currentDone.includes(vaxId)) {
        newDone = currentDone.filter(id => id !== vaxId);
    } else {
        newDone = [...currentDone, vaxId];
    }
    const newSettings = { ...settings, vaccinationsDone: newDone };
    setSettings(newSettings);
    StorageService.setItem('bloom_settings', JSON.stringify(newSettings));
  };

  const handleReset = () => {
    StorageService.clear();
    setTimeout(() => {
        window.location.reload();
    }, 50);
  };

  if (loading) return <div className="h-screen flex items-center justify-center bg-bloom-light dark:bg-deep-bg text-bloom-DEFAULT animate-pulse">Loading Bloom...</div>;

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (!settings) {
    return (
      <>
        <div className="fixed top-4 right-4 z-50">
           <button onClick={() => setDarkMode(!darkMode)} className="p-3 rounded-full bg-white dark:bg-deep-card shadow-lg text-bloom-DEFAULT dark:text-yellow-400">
             {darkMode ? <Sun size={20} /> : <Moon size={20} />}
           </button>
        </div>
        <Onboarding onComplete={handleOnboardingComplete} />
      </>
    );
  }

  // Determine Nav Items
  let navItems = [];
  if (isPlanning) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Calendar, label: 'Cycle & Plan' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Body Ready' },
          { id: TabView.PARTNER, icon: Users, label: 'Partner' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' }
      ];
  } else if (isPostpartum) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Baby, label: 'Baby Care' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Growth & Vitals' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' }, 
          { id: TabView.DIET, icon: Utensils, label: 'Mom Diet' }
      ];
  } else {
      navItems = [
          { id: TabView.DASHBOARD, icon: LayoutDashboard, label: 'Dashboard' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Vitals' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' },
          { id: TabView.TIMELINE, icon: Calendar, label: 'Timeline' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.DIET, icon: Utensils, label: 'Diet Plan' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' },
          { id: TabView.REPORTS, icon: FileText, label: 'Reports' },
      ];
  }

  const renderContent = () => {
    const calcSafe = calculations || { 
        currentWeek: 0, edd: new Date(), currentDay: 0, totalDays: 0, trimester: 1, month: 1, progressPercent: 0 
    } as PregnancyCalculations;

    const profileKey = settings.id;

    switch(activeTab) {
      case TabView.DASHBOARD: 
        if (isPlanning) return <PrePregnancyDashboard key={`plan_${profileKey}`} settings={settings} onUpdateSettings={handleUpdateProfile} />;
        if (isPostpartum) return <PostpartumDashboard key={`pp_${profileKey}`} settings={settings} />;
        return <Dashboard key={`preg_${profileKey}`} calculations={calcSafe} settings={settings} />;
      case TabView.TIMELINE: return <Timeline key={`time_${profileKey}`} calculations={calcSafe} settings={settings} />;
      case TabView.REPORTS: return <ReportAnalyzer key={`rep_${profileKey}`} />;
      case TabView.MEDICINES: 
        return <MedicineTracker 
            key={`med_${profileKey}`} 
            currentWeek={calcSafe.currentWeek} 
            isPostpartum={isPostpartum} 
            mode={settings.status}
            comorbidities={settings.comorbidities}
        />;
      case TabView.DIET: return <DietPlan key={`diet_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.VACCINATIONS: 
        return <VaccinationTracker 
            key={`vax_${profileKey}`}
            settings={settings} 
            currentWeek={isPostpartum ? getBabyAgeInWeeks() : calcSafe.currentWeek} 
            onUpdate={handleVaccineUpdate} 
        />;
      case TabView.HEALTH: return <HealthTracker key={`health_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.TOOLS: return <ToolsHub key={`tools_${profileKey}`} />;
      case TabView.PARTNER: return <MalePartnerHealth key={`partner_${profileKey}`} />;
      case TabView.PROFILE: 
        return <Profile 
            key={`prof_${profileKey}`}
            settings={settings} 
            profiles={profiles} 
            onUpdate={handleUpdateProfile} 
            onReset={handleReset} 
            onAddProfile={handleAddProfile}
            onSwitchProfile={handleSwitchProfile}
        />;
      default: return null;
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-bloom-light dark:bg-deep-bg transition-colors duration-300">
      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex w-64 flex-col bg-white dark:bg-deep-card border-r border-gray-200 dark:border-deep-border shrink-0 h-full">
         <div className="p-6">
             <h1 className={`text-2xl font-bold bg-clip-text text-transparent ${bgGradient}`}>
                {isPlanning ? "Bloom Plan" : isPostpartum ? (settings.babyGender === 'boy' ? "Bloom Baby" : "Bloom Baby") : "Bloom Bump"}
             </h1>
             {profiles.length > 1 && (
                 <div className="mt-2 flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab(TabView.PROFILE)}>
                     <div className="flex -space-x-2">
                         {profiles.slice(0, 3).map(p => (
                             <div key={p.id} className="w-6 h-6 rounded-full border border-white bg-gray-200 flex items-center justify-center text-[10px] overflow-hidden">
                                 {p.babyName ? p.babyName[0] : p.name[0]}
                             </div>
                         ))}
                     </div>
                     <span className="text-xs text-gray-500 underline">Switch Profile</span>
                 </div>
             )}
         </div>

         <nav className="flex-1 p-4 space-y-2 overflow-y-auto custom-scrollbar">
            {navItems.map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium ${activeTab === item.id ? `${activeBg} shadow-lg` : 'text-gray-700 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}
               >
                  <item.icon size={20} />
                  {item.label}
               </button>
            ))}
         </nav>

         <div className="p-4 border-t border-gray-200 dark:border-deep-border mt-auto">
            <div 
              onClick={() => setActiveTab(TabView.PROFILE)}
              className="flex items-center gap-3 px-4 py-3 rounded-xl bg-gray-100 dark:bg-slate-800/50 mb-2 cursor-pointer hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
            >
                <div className={`w-8 h-8 rounded-full ${badgeColor} flex items-center justify-center font-bold`}>
                    {settings.name.charAt(0).toUpperCase()}
                </div>
                <div className="flex-1 overflow-hidden">
                    <p className="text-sm font-bold truncate text-gray-800 dark:text-white">{settings.babyName || settings.name}</p>
                    <p className="text-xs text-gray-500 truncate capitalize">
                        {settings.status === 'postpartum' && settings.babyName ? 'Baby Profile' : settings.status}
                    </p>
                </div>
                <Settings size={16} className="text-gray-400" />
            </div>
            <button 
              onClick={handleLogout}
              className="w-full flex items-center gap-2 px-4 py-2 text-sm text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
            >
              <LogOut size={16} /> Sign Out
            </button>
         </div>
      </aside>

      {/* Mobile Nav - Fixed Bottom */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-deep-card border-t border-gray-200 dark:border-deep-border z-50 flex flex-col safe-area-bottom shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
         <div className="flex items-center gap-1 overflow-x-auto px-2 py-2 w-full no-scrollbar">
            {[
              ...navItems,
              { id: TabView.PROFILE, icon: User, label: 'Profile' },
            ].map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`flex-shrink-0 flex flex-col items-center gap-1 p-2 rounded-xl transition-all min-w-[64px] ${activeTab === item.id ? themeColor : 'text-gray-400'}`}
               >
                  <item.icon size={22} />
                  <span className="text-[10px] font-medium whitespace-nowrap">{item.label}</span>
               </button>
            ))}
         </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
         <header className="h-16 flex items-center justify-between px-4 md:px-8 border-b border-gray-200 dark:border-deep-border bg-white/50 dark:bg-deep-card/50 backdrop-blur-md sticky top-0 z-40 shrink-0">
            <div className="flex items-center gap-2">
                <h2 className="text-lg md:text-xl font-bold text-gray-800 dark:text-white capitalize truncate">
                    {activeTab === TabView.VACCINATIONS ? 'Vaccinations' : activeTab.replace('-', ' ')}
                </h2>
                {profiles.length > 1 && (
                    <span className="text-xs px-2 py-0.5 rounded-full bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-gray-400 border border-gray-200 dark:border-slate-700 hidden md:inline-block">
                        Active: {settings.babyName || "Profile 1"}
                    </span>
                )}
            </div>
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 rounded-full bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-gray-600 dark:text-yellow-400 transition-colors shadow-sm"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
         </header>

         <div className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 pb-28 md:pb-8 custom-scrollbar scroll-smooth w-full">
            <div className="max-w-7xl mx-auto w-full">
              {renderContent()}
            </div>
         </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { PregnancyCalculations, WeeklyInfo, UserSettings, Medicine } from '../types';
import { WEEKLY_DATA, FALLBACK_WEEKLY_INFO, SCAN_SCHEDULE, LAB_SCHEDULE, MATERNAL_VACCINES, MATERNAL_AGE_RISKS, OBSTETRIC_HISTORY_RISKS, TIP_LIBRARY, COMORBIDITY_GUIDELINES } from '../constants';
import { getPregnancyAdvice } from '../services/geminiService';
import { Button } from './Button';
import { Info, Baby, AlertCircle, Bell, RotateCcw, Syringe, Sparkles, FlaskConical, ShieldAlert, Key, CheckCircle2, Lightbulb, Pill, Ruler, ChevronLeft, ChevronRight } from 'lucide-react';
import { StorageService } from '../services/storage';

interface Props {
  calculations: PregnancyCalculations;
  settings: UserSettings;
}

export const Dashboard: React.FC<Props> = ({ calculations, settings }) => {
  const [selectedWeek, setSelectedWeek] = useState(calculations.currentWeek);
  const [todaysMedicines, setTodaysMedicines] = useState<Medicine[]>([]);

  useEffect(() => {
    setSelectedWeek(calculations.currentWeek);
  }, [calculations.currentWeek]);

  useEffect(() => {
      const isPostpartum = settings.status === 'postpartum';
      const key = isPostpartum ? 'bloom_pp_medicines' : 'bloom_medicines';
      const stored = StorageService.getItem(key);
      if (stored) {
          const parsed: Medicine[] = JSON.parse(stored);
          setTodaysMedicines(parsed.filter(m => !m.taken));
      } else {
          setTodaysMedicines([]);
      }
  }, [settings.status]);

  const displayTrimester = selectedWeek <= 13 ? 1 : selectedWeek <= 27 ? 2 : 3;
  const displayMonth = Math.ceil(selectedWeek / 4.3);
  const displayProgress = Math.min((selectedWeek / 40) * 100, 100);

  const availableWeeks = Object.keys(WEEKLY_DATA).map(Number).sort((a, b) => a - b);
  const closestWeek = availableWeeks.reduce((prev, curr) => 
    Math.abs(curr - selectedWeek) < Math.abs(prev - selectedWeek) ? curr : prev
  );

  const weekInfo: WeeklyInfo = WEEKLY_DATA[selectedWeek] || WEEKLY_DATA[closestWeek] || FALLBACK_WEEKLY_INFO;

  const relevantScans = SCAN_SCHEDULE.filter(scan => {
    return (selectedWeek >= scan.weekStart - 1 && selectedWeek <= scan.weekEnd);
  });

  const relevantLabs = LAB_SCHEDULE.filter(lab => {
      const isTime = selectedWeek >= lab.weekStart - 1 && selectedWeek <= lab.weekEnd;
      if (!isTime) return false;
      if (lab.condition) {
          if (lab.condition === 'thyroid' && !settings.comorbidities.includes('thyroid')) return false;
          if (lab.condition === 'anemia' && !settings.comorbidities.includes('anemia')) return false;
          if (lab.condition === 'rh_negative' && (!settings.maternalBloodGroup || !settings.maternalBloodGroup.includes('-'))) return false;
      }
      return true;
  });

  const vaccinationsDone = settings.vaccinationsDone || [];
  const upcomingVaccines = MATERNAL_VACCINES.filter(vax => {
    const isDone = vaccinationsDone.includes(vax.id);
    return !isDone && (selectedWeek >= vax.dueWeekStart - 2 && selectedWeek <= vax.dueWeekEnd + 4);
  });

  const selectedComorbidities = settings.comorbidities || [];

  const [question, setQuestion] = useState('');
  const [aiAnswer, setAiAnswer] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [missingKey, setMissingKey] = useState(false);

  const askAi = async () => {
    if (!question.trim()) return;
    setLoadingAi(true);
    setMissingKey(false);

    const answer = await getPregnancyAdvice(question, selectedWeek);

    if (answer === "MISSING_KEY") {
        setMissingKey(true);
        setAiAnswer(null);
    } else {
        setAiAnswer(answer);
    }

    setLoadingAi(false);
  };

  const handlePrevWeek = () => {
    if (selectedWeek > 1) setSelectedWeek(p => p - 1);
  };

  const handleNextWeek = () => {
    if (selectedWeek < 42) setSelectedWeek(p => p + 1);
  };

  const handleResetToCurrent = () => {
    setSelectedWeek(calculations.currentWeek);
  };

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);
  const minSwipeDistance = 50;

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;

    if (isLeftSwipe) handleNextWeek();
    if (isRightSwipe) handlePrevWeek();
  };

  const calculateRiskProfile = () => {
      const risks: string[] = [];
      const actions: string[] = [];
      let level: 'Low' | 'Moderate' | 'High' = 'Low';

      const age = settings.age;
      if (age) {
          if (age < 18) {
              level = 'Moderate';
              risks.push(MATERNAL_AGE_RISKS.teenage.label);
              actions.push(MATERNAL_AGE_RISKS.teenage.action);
          } else if (age > 35) {
              level = 'High';
              risks.push(MATERNAL_AGE_RISKS.advanced.label);
              actions.push(MATERNAL_AGE_RISKS.advanced.action);
          }
      }

      if (settings.heightCm && settings.prePregnancyWeight) {
          const bmi = settings.prePregnancyWeight / ((settings.heightCm / 100) ** 2);
          if (bmi > 30) {
              level = 'High';
              risks.push("Obesity (BMI > 30)");
              actions.push("High risk of GDM/HTN. Early GTT required. Monitor fetal growth.");
          } else if (bmi < 18.5) {
              level = level === 'High' ? 'High' : 'Moderate';
              risks.push("Underweight (BMI < 18.5)");
              actions.push("Risk of IUGR (Small Baby). Increase caloric intake.");
          }
      }

      if (settings.heightCm && settings.heightCm < 145) {
          level = level === 'High' ? 'High' : 'Moderate';
          risks.push("Short Stature (<145cm)");
          actions.push("Risk of Cephalo-Pelvic Disproportion (CPD). Hospital delivery mandatory.");
      }

      if (selectedComorbidities.length > 0) {
          level = 'High';
          selectedComorbidities.forEach(id => {
              const guide = COMORBIDITY_GUIDELINES[id];
              if (guide) {
                  risks.push(guide.name);
                  if (guide.monitoring) {
                      actions.push(`${guide.name}: ${guide.monitoring[0]}`);
                  }
              }
          });
      }

      const obs = settings.obstetricHistory;
      if (obs) {
          if (obs.abortionsT1 >= 2) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.action);
          }
          if (obs.abortionsT2 >= 1) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.t2_loss.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.t2_loss.action);
          }
          if (obs.lastBabyCongenitalDefect) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.action);
          }
          if (obs.para >= 4) {
              level = 'High';
              risks.push("Grand Multipara (Para ≥ 4)");
              actions.push("High risk of PPH and Anemia. Active management of labor required.");
          }
      }

      return { level, risks, actions };
  };

  const riskProfile = calculateRiskProfile();

  const isFuture = selectedWeek > calculations.currentWeek;
  const isPast = selectedWeek < calculations.currentWeek;

  let currentTip = "";
  if (weekInfo.dailyTips && weekInfo.dailyTips.length > 0) {
      const dayIndex = selectedWeek === calculations.currentWeek 
          ? (calculations.currentDay % 7) 
          : 0; 
      currentTip = weekInfo.dailyTips[dayIndex] || weekInfo.dailyTips[0];
  } else {
      currentTip = "Stay hydrated and rest well. Listen to your body.";
  }

  const hasBiometry = weekInfo.biometry && (Object.keys(weekInfo.biometry).length > 0);

  return (
    <div className="space-y-8 animate-fade-in pb-10">
      {(isFuture || isPast) && (
        <div className="flex justify-center -mb-4 z-10 relative">
          <button onClick={handleResetToCurrent} className="flex items-center gap-2 px-4 py-2 bg-pink-100 dark:bg-pink-900/30 text-pink-700 dark:text-pink-300 rounded-full text-sm font-bold hover:bg-pink-200 transition-colors shadow-sm">
            <RotateCcw size={14} /> Back to Current Week ({calculations.currentWeek})
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="col-span-1 md:col-span-2 bg-gradient-to-br from-pink-600 to-purple-700 rounded-3xl p-6 text-white shadow-xl shadow-pink-500/20 relative overflow-hidden select-none" onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>
            <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl pointer-events-none"></div>
            <button onClick={handlePrevWeek} disabled={selectedWeek <= 1} className="absolute left-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"><ChevronLeft size={24} /></button>
            <button onClick={handleNextWeek} disabled={selectedWeek >= 42} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"><ChevronRight size={24} /></button>

            <div className="relative z-10 flex flex-col md:flex-row items-center gap-8 justify-center md:justify-start">
                <div className="relative w-40 h-40 flex-shrink-0">
                    <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                        <circle className="text-white/20 stroke-current" strokeWidth="8" cx="50" cy="50" r="40" fill="transparent"></circle>
                        <circle className="text-white stroke-current transition-all duration-500 ease-out" strokeWidth="8" strokeLinecap="round" cx="50" cy="50" r="40" fill="transparent" strokeDasharray="251.2" strokeDashoffset={251.2 - (251.2 * displayProgress) / 100}></circle>
                    </svg>
                    <div className="absolute top-0 left-0 w-full h-full flex flex-col items-center justify-center text-center">
                        <span className="text-4xl font-bold">{selectedWeek}</span>
                        <span className="text-sm font-medium opacity-80">{selectedWeek === calculations.currentWeek ? `+ ${calculations.currentDay}d` : 'Weeks'}</span>
                    </div>
                </div>

                <div className="text-center md:text-left space-y-2">
